{
  "ok": true,
  "server": "candidate-time",
  "sourceType": "stdio",
  "timeoutMs": 120000,
  "toolCount": 2,
  "tools": [
    {
      "description": "Get current time in a specific timezones",
      "inputSchema": {
        "properties": {
          "timezone": {
            "description": "IANA timezone name (e.g., 'America/New_York', 'Europe/London'). Use 'Europe/Moscow' as local timezone if no timezone provided by the user.",
            "type": "string"
          }
        },
        "required": [
          "timezone"
        ],
        "type": "object"
      },
      "name": "get_current_time"
    },
    {
      "description": "Convert time between timezones",
      "inputSchema": {
        "properties": {
          "source_timezone": {
            "description": "Source IANA timezone name (e.g., 'America/New_York', 'Europe/London'). Use 'Europe/Moscow' as local timezone if no source timezone provided by the user.",
            "type": "string"
          },
          "target_timezone": {
            "description": "Target IANA timezone name (e.g., 'Asia/Tokyo', 'America/San_Francisco'). Use 'Europe/Moscow' as local timezone if no target timezone provided by the user.",
            "type": "string"
          },
          "time": {
            "description": "Time to convert in 24-hour format (HH:MM)",
            "type": "string"
          }
        },
        "required": [
          "source_timezone",
          "time",
          "target_timezone"
        ],
        "type": "object"
      },
      "name": "convert_time"
    }
  ]
}

