function Add-Event([string]$name, [object]$data) {
  $events.Add([pscustomobject]@{ name = $name; at = (Get-Date).ToString('o'); data = $data }) | Out-Null
}
function Invoke-McpTool([string]$toolName, [hashtable]$toolArguments, [int]$timeoutSeconds = 180) {
  $script:requestId += 1
  $bodyObject = @{ jsonrpc = '2.0'; id = $script:requestId; method = 'tools/call'; params = @{ name = $toolName; arguments = $toolArguments } }
  $body = $bodyObject | ConvertTo-Json -Depth 80 -Compress
  $started = Get-Date
  try {
    $response = Invoke-RestMethod -Uri 'http://127.0.0.1:39022/mcp' -Method Post -Headers $headers -Body $body -TimeoutSec $timeoutSeconds
    $elapsed = [int]((Get-Date) - $started).TotalMilliseconds
    $structured = $null
    if ($response.result -and $response.result.structuredContent) {
      $structured = $response.result.structuredContent
    } elseif ($response.result -and $response.result.content -and $response.result.content.Count -gt 0 -and $response.result.content[0].text) {
      try { $structured = $response.result.content[0].text | ConvertFrom-Json -Depth 80 } catch { $structured = $response.result.content[0].text }
    }
    return [pscustomobject]@{ ok = $true; httpOk = $true; elapsedMs = $elapsed; resultIsError = [bool]($response.result.isError); structured = $structured; raw = $response }
  } catch {
    $elapsed = [int]((Get-Date) - $started).TotalMilliseconds
    return [pscustomobject]@{ ok = $false; httpOk = $false; elapsedMs = $elapsed; error = $_.Exception.Message }
  }
}
function Set-McpServer([object]$servers, [string]$name, [hashtable]$definition) {
  if ($servers.PSObject.Properties.Name -contains $name) { $servers.PSObject.Properties.Remove($name) }
